4717 Constant *llvm::getLosslessInvCast(Constant *C, Type *InvCastTo,
4718                                    unsigned CastOp, const DataLayout &DL,
4719                                    PreservedCastFlags *Flags) {
4720   switch (CastOp) {
4721   case Instruction::BitCast:
4722     // Bitcast is always lossless.
4723     return ConstantFoldCastOperand(Instruction::BitCast, C, InvCastTo, DL);
4724   case Instruction::Trunc: {
4725     auto *ZExtC = ConstantFoldCastOperand(Instruction::ZExt, C, InvCastTo, DL);
4726     if (Flags) {
4727       // Truncation back on ZExt value is always NUW.
4728       Flags->NUW = true;
4729       // Test positivity of C.
4730       auto *SExtC =
4731           ConstantFoldCastOperand(Instruction::SExt, C, InvCastTo, DL);
4732       Flags->NSW = ZExtC == SExtC;
4733     }
4734     return ZExtC;
4735   }
4736   case Instruction::SExt:
4737   case Instruction::ZExt: {
4738     auto *InvC = ConstantExpr::getTrunc(C, InvCastTo);
4739     auto *CastInvC = ConstantFoldCastOperand(CastOp, InvC, C->getType(), DL);
4740     // Must satisfy CastOp(InvC) == C.
4741     if (!CastInvC || CastInvC != C)
4742       return nullptr;
4743     if (Flags && CastOp == Instruction::ZExt) {
4744       auto *SExtInvC =
4745           ConstantFoldCastOperand(Instruction::SExt, InvC, C->getType(), DL);
4746       // Test positivity of InvC.
4747       Flags->NNeg = CastInvC == SExtInvC;
4748     }
4749     return InvC;
4750   }
4751   case Instruction::FPExt: {
4752     Constant *InvC =
4753         ConstantFoldCastOperand(Instruction::FPTrunc, C, InvCastTo, DL);
4754     if (InvC) {
4755       Constant *CastInvC =
4756           ConstantFoldCastOperand(CastOp, InvC, C->getType(), DL);
4757       if (CastInvC == C)
4758         return InvC;
4759     }
4760     return nullptr;
4761   }
4762   default:
4763     return nullptr;
4764   }
